import os
from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

DEPT_ABBREVS = {
    'animation': ['anm', 'anim', 'ani'],
    'compositing': ['cmp', 'comp'],
    'fx': ['fx', 'effects', 'vfx'],
    'effects': ['fx', 'vfx'],
    'lighting': ['lgt', 'light', 'lit'],
    'layout': ['lay'],
    'cfx': ['cfx', 'charfx'],
    'character fx': ['cfx'],
    'modeling': ['mod', 'model'],
    'rigging': ['rig'],
    'texturing': ['tex', 'texture'],
    'rendering': ['rnd', 'render'],
    'matchmove': ['mm', 'mmv'],
    'roto': ['rot'],
    'paint': ['pnt'],
}

class PrismGetEntityPathNode(BaseNode):
    name = "Prism: Get Entity Path"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("entity", "dict")
        self.add_input("department", "string", widget_type="text", default="")
        self.add_input("task", "string", widget_type="text", default="")
        self.add_output("entity_root", "string")
        self.add_output("dept_path", "string")
        self.add_output("task_path", "string")
        self.add_output("found", "bool")

    def _resolve_dept_folder(self, scenes_root, dept):
        dept_lower = dept.lower()
        candidates = {dept_lower}
        candidates.update(DEPT_ABBREVS.get(dept_lower, []))
        for key, vals in DEPT_ABBREVS.items():
            if dept_lower in vals:
                candidates.add(key)
                candidates.update(vals)
        for entry in os.scandir(scenes_root):
            if entry.is_dir() and entry.name.lower() in candidates:
                return entry.path
        return None

    async def execute(self, inputs):
        entity = inputs.get("entity") or {}
        dept = (inputs.get("department") or "").strip()
        task = (inputs.get("task") or "").strip()
        defaults = {"entity_root": "", "dept_path": "", "task_path": "", "found": False}
        entity_root = entity.get("path", "").strip()
        if not entity_root:
            self.log_error("Entity has no path — connect output from prism_get_shot_by_sequence.")
            return defaults
        if not os.path.isdir(entity_root):
            self.log_error(f"Entity path does not exist: {entity_root}")
            return defaults
        dept_path = ""
        task_path = ""
        if dept:
            scenes_root = None
            for candidate in ("Scenefiles", "Scenes", "scenes", "scenefiles"):
                p = os.path.join(entity_root, candidate)
                if os.path.isdir(p):
                    scenes_root = p
                    break
            if scenes_root:
                folder = self._resolve_dept_folder(scenes_root, dept)
                if folder:
                    dept_path = folder
                else:
                    available = [e.name for e in os.scandir(scenes_root) if e.is_dir()]
                    self.log_error(f"Dept '{dept}' not found — available: {available}")
            else:
                self.log_error(f"No Scenefiles folder in {entity_root}")
        if dept_path and os.path.isdir(dept_path):
            available_tasks = [e.name for e in os.scandir(dept_path) if e.is_dir()]
            self.log_info(f"tasks in dept folder: {available_tasks}")
        if task and dept_path:
            task_candidates = {task, task.lower()}
            task_candidates.update(DEPT_ABBREVS.get(task.lower(), []))
            for key, vals in DEPT_ABBREVS.items():
                if task.lower() in vals:
                    task_candidates.add(key)
                    task_candidates.update(vals)
            found_task = None
            for entry in (os.scandir(dept_path) if os.path.isdir(dept_path) else []):
                if entry.is_dir() and (entry.name == task or entry.name.lower() in task_candidates):
                    found_task = entry.path
                    break
            if found_task:
                task_path = found_task
            else:
                available = [e.name for e in os.scandir(dept_path) if e.is_dir()] if os.path.isdir(dept_path) else []
                self.log_error(f"Task '{task}' not found — available: {available}")
        self.log_info(f"entity_root={entity_root}")
        if dept_path:
            self.log_info(f"dept_path={dept_path}")
        if task_path:
            self.log_info(f"task_path={task_path}")
        return {"entity_root": entity_root, "dept_path": dept_path,
                "task_path": task_path, "found": True}

def register_node():
    return PrismGetEntityPathNode
